  ('elementary-0a2fc18c-moex-00304', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-113-55d283b0', 'sub-elementary-0a2fc18c-03', NULL, 'single_choice', '下列何者非屬我國行政程序法上所規範之行政行為？', '["行政處分", "直接強制", "法規命令", "行政指導"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:15+00:00", "source_pdf_sha1": "4cff5c1bfc40", "answer_pdf_sha1": "f53769d74470", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "511", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
